import re


def fix_indentation(code_line, spaces=4):
    stripped = code_line.lstrip()
    if not stripped:
        return ''
    leading = code_line[:len(code_line) - len(stripped)]
    indent_count = 0
    for ch in leading:
        if ch == '\t':
            indent_count += spaces
        else:
            indent_count += 1
    level = indent_count // spaces
    return ' ' * (level * spaces) + stripped


def is_snake_case(name):
    if not name:
        return False
    return bool(re.match(r'^[a-z][a-z0-9]*(_[a-z0-9]+)*$', name))


def fix_line_length(line, max_len=79):
    if len(line) <= max_len:
        return [line]
    words = line.split()
    chunks = []
    current = ''
    for word in words:
        if not current:
            current = word
        elif len(current) + 1 + len(word) <= max_len:
            current += ' ' + word
        else:
            chunks.append(current)
            current = word
    if current:
        chunks.append(current)
    return chunks


def count_style_issues(lines):
    issues = {'trailing_whitespace': 0, 'tabs': 0, 'long_lines': 0}
    for line in lines:
        if line != line.rstrip():
            issues['trailing_whitespace'] += 1
        if '\t' in line:
            issues['tabs'] += 1
        if len(line) > 79:
            issues['long_lines'] += 1
    return issues
